'use client';

import Link from 'next/link';
import { useParams } from 'next/navigation';
import { useSiteSettings } from '@/hooks/useSiteSettings';

interface ConditionalContactSalesProps {
  className?: string;
  variant?: 'desktop' | 'mobile';
}

export function ConditionalContactSales({ 
  className = '', 
  variant = 'desktop' 
}: ConditionalContactSalesProps) {
  const { settings, isLoading } = useSiteSettings();
  const params = useParams();
  const currentLang = params?.lang || 'en';

  if (isLoading) {
    return (
      <div className={`animate-pulse bg-gray-200 dark:bg-gray-700 rounded ${
        variant === 'mobile' ? 'h-12 w-full' : 'h-8 w-24'
      } ${className}`} />
    );
  }

  if (!settings.contactSales.show) {
    return null;
  }

  const baseClasses = variant === 'mobile' 
    ? "flex justify-center items-center w-full h-12 border-0 rounded-lg bg-neutral-100 dark:bg-white/10 text-neutral-600 dark:text-neutral-300 font-semibold text-lg transition-colors duration-200 hover:bg-neutral-200 dark:hover:bg-white/15"
    : "hidden sm:flex items-center h-8 px-3 border-0 rounded-lg bg-neutral-100 dark:bg-white/10 hover:bg-neutral-200 dark:hover:bg-white/15 text-neutral-600 dark:text-neutral-300 font-semibold text-sm leading-4 tracking-tight transition-colors duration-200";

  return (
    <Link
      href={`/${currentLang}${settings.contactSales.url}`}
      className={`${baseClasses} ${className}`}
    >
      {settings.contactSales.text}
    </Link>
  );
}